#include<bits/stdc++.h>
using namespace std;

const int N = 5e5 + 5;

vector<int> e[N];
int fa[N][25], dep[N];

void dfs(int u, int f)
{
    fa[u][0] = f;
    dep[u] = dep[f] + 1;
    for(int i = 1; i <= 19; i++)
        fa[u][i] = fa[fa[u][i - 1]][i - 1];
    for(int v : e[u])
        if(v != f)
            dfs(v, u);
}

int LCA(int x, int y)
{
    if(dep[x] > dep[y]) swap(x, y);
    for(int i = 19; i >= 0; i--)
        if(dep[fa[y][i]] >= dep[x]) 
            y = fa[y][i];
    if(x == y) return x;
    for(int i = 19; i >= 0; i--)
        if(fa[x][i] != fa[y][i]) 
            x = fa[x][i], y = fa[y][i];
    return fa[x][0];
}

int main()
{
    cin.tie(0) -> sync_with_stdio(0);
    int n, m, s;
    cin >> n >> m >> s;
    for(int i = 1; i < n; i++)
    {
        int x, y;
        cin >> x >> y;
        e[x].push_back(y);
        e[y].push_back(x);
    }
    dfs(s, s);
    for(int i = 1; i <= m; i++)
    {
        int x, y;
        cin >> x >> y;
        cout << LCA(x, y) << '\n';
    }
    return 0;
}
